        "</xs:schema>";

    XmlSchemaSet schemas;
    schemas.AddXml(schemaXml);

    const auto valid = XmlDocument::Parse(
        "<season xmlns=\"urn:gmonth-types\" month=\"--04Z\" day=\"---20\" marker=\"--03-20Z\"/>");
    valid->Validate(schemas);

    bool threw = false;
